import torch, subprocess, sys
from model import build_model_from_checkpoint
for p in ['checkpoints/ema_weighted.pt','checkpoints/improved.pt','checkpoints/baseline.pt','checkpoints/fixed_retrain.pt']:
    try:
        ckpt = torch.load(p, map_location='cpu', weights_only=False)
    except TypeError:
        ckpt = torch.load(p, map_location='cpu')
    try:
        m,v = build_model_from_checkpoint(ckpt, device='cpu')
        print(p, 'OK', v)
    except Exception as e:
        print(p, 'FAIL', repr(e))
ret = subprocess.run([sys.executable, 'predict.py', '--data_path', 'local_test', '--checkpoint', 'checkpoints/ema_weighted.pt', '--output', 'local_test/output.json'], check=False)
print('predict_exit', ret.returncode)
